use indoc::indoc;
use nu_test_support::{fs::Stub::FileWithContent, prelude::*};

#[test]
fn table_pagging_row_offset_overlap() -> Result {
    let actual: String = test().run("0..1000 | table")?;
    let rows = (0..1000)
        .map(|i| format!("в”‚{i:>4} в”‚{i:>4} в”‚"))
        .collect::<Vec<_>>()
        .join("\n");
    let expected = format!(
        "{}\n{}\n{}",
        "в•­в”Ђв”Ђв”Ђв”Ђв”Ђв”¬в”Ђв”Ђв”Ђв”Ђв”Ђв•®",
        rows,
        indoc! {"
            в•°в”Ђв”Ђв”Ђв”Ђв”Ђв”ґв”Ђв”Ђв”Ђв”Ђв”Ђв•Ї
            в•­в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”¬в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв•®
            в”‚ 1000 в”‚ 1000 в”‚
            в•°в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”ґв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв•Ї
        "}
    );
    assert_eq!(actual, expected);
    Ok(())
}

#[test]
fn table_index_0() -> Result {
    let actual: String = test().run("[1 3 1 3 2 1 1] | table")?;
    assert_eq!(
        actual,
        indoc! {"
            в•­в”Ђв”Ђв”Ђв”¬в”Ђв”Ђв”Ђв•®
            в”‚ 0 в”‚ 1 в”‚
            в”‚ 1 в”‚ 3 в”‚
            в”‚ 2 в”‚ 1 в”‚
            в”‚ 3 в”‚ 3 в”‚
            в”‚ 4 в”‚ 2 в”‚
            в”‚ 5 в”‚ 1 в”‚
            в”‚ 6 в”‚ 1 в”‚
            в•°в”Ђв”Ђв”Ђв”ґв”Ђв”Ђв”Ђв•Ї
        "}
    );
    Ok(())
}

